previewCss:
.darma-loader-elastic-dots {
  display: inline-flex;
  gap: 7px;
  color: #6366f1;
}
.darma-loader-elastic-dots b {
  width: 11px;
  height: 11px;
  border-radius: 999px;
  background: currentColor;
  transform-origin: center;
  animation: darma-loader-elastic-dots-elastic 0.9s ease-in-out infinite;
}
.darma-loader-elastic-dots b:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-elastic-dots b:nth-child(3) { animation-delay: 0.24s; }
@keyframes darma-loader-elastic-dots-elastic {
  0%, 100% { transform: scaleY(1); opacity: 0.45; }
  45% { transform: scaleY(2.1); opacity: 1; }
}

